INSERT INTO `abouts` (`id`, `title`, `subtitle`, `cover_image`, `content`, `type`, `lang`, `is_open`, `is_hot`, `weight`, `created_at`, `updated_at`) VALUES
(8, '关于我们', '', NULL, '<h3>娱乐 ． 创新 ． 合法</h3>\n<p>&ldquo;亚新娱乐&rdquo;目前拥有菲律宾合法注册之博彩公司 ，一切博彩营业行为皆遵从哥斯特黎加政府的博彩条约。 我们在日渐热络的网络博彩市场中，不断求新求变，以傲人的创意团队开发各种游戏方式。为客户提供即时、 刺激、体贴的娱乐产品与高质量服务，是本公司创建&ldquo;亚新娱乐&rdquo;的首要宗旨。</p>\n<h3>以专业、公正的科技背景满足各种娱乐需求</h3>\n<p>&ldquo;亚新娱乐&rdquo;在运动博彩上投注大量的人力与资源，更由顶级的盘房进行专业操盘，提供完整赛事、 搭配 丰富的玩法组合给热爱体育的玩家。 真人视讯 &mdash;我们所聘任的荷官均须接受严格的国际赌场专业训练与认证，进行各种赌场游戏时，所有赌局都依 荷官动作做出反应，而不是无趣的计算机机率默认结果。高科技的网络直播技术，更能带给您亲历赌场的刺激经验！ 彩票游戏&mdash;官方赛事结果正是本类游戏唯一的胜负标准，让玩家在活泼的投注接口中，享受最公正的娱乐。 电子游戏&mdash;使用最公平的随机数生成机率，让您安心享受多元、炫丽的娱乐性游戏。&ldquo;亚新娱乐&rdquo;所有游戏共同的优点 &mdash; 不须耗时下载；接口简单明了；操作功能齐全； 画面精致优雅；游戏结果公平、公正、公开！</p>\n<h3>良好的商誉．安全、隐密的网络环境</h3>\n<p>在竞争激烈的博彩市场中，&ldquo;亚新娱乐&rdquo;向来是众多玩家一致的选择，除了因为多元化的娱乐产品使人流连 忘返、更因为高质量的服务以及&ldquo;亚新娱乐&rdquo;长久以来的良好信誉在广大玩家群众之间建立了口碑。 我们的用心随处可见，并且获得了GEOTRUST的权威性国际认证，以确保网站活动的公平、 公正，所有会员数据均经加密处理，保障玩家隐私。 &ldquo;亚新娱乐&rdquo;以服务不打烊的精神，全天候24小时处理会员出入款的相关事宜，严格训练的客服团队，以专业、亲 切的态度解决您对于网站、游戏的种种疑难杂症，让每位玩家有宾至如归的感觉！ &ldquo;亚新娱乐&rdquo;以业界前所未见的各种优惠方式回馈我们的会员，绝对是玩家最明智的选择！</p>', 1, 'zh_cn', 1, 0, 5, '2020-05-08 07:52:44', '2020-05-08 08:09:42'),
(21, '存款帮助', '', NULL, '<table>\n<thead>\n<tr>\n<th>存款方式</th>\n<th>转账形式</th>\n<th>充值渠道</th>\n<th>到账时间</th>\n<th>交易限额</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>公司入款</td>\n<td>先提交订单后充值</td>\n<td>云闪付扫码、银行卡充值</td>\n<td>实时到账</td>\n<td>10RMB-无上限</td>\n</tr>\n<tr>\n<td>线上存款</td>\n<td>先提交订单后充值</td>\n<td>支付宝扫码、微信扫码、网银支付、银联扫码</td>\n<td>实时到账</td>\n<td>10RMB-无上限</td>\n</tr>\n</tbody>\n</table>\n<h3>1.如何为账号充值</h3>\n<p>A：选择公司入款<br />充值渠道：&ldquo;银行卡充值&rdquo;&ldquo;云闪付扫码&rdquo;；<br />B：选择线上存款<br />充值渠道：&ldquo;支付宝扫码&rdquo;、&ldquo;微信扫码&rdquo;、&ldquo;网银支付&rdquo;&ldquo;银联扫码&rdquo;</p>\n<h3>2.充值操作指南：</h3>\n<p>手机端：a：点击首页左下角【财务中心】<br />b：选择【公司入款】、【银联扫码支付】、【微信支付】、【支付宝支付】<br />c：选择支付方式后提交订单，充值即可。</p>\n<p>电脑端：a：点击首页右上角【线上存款】<br />b：选择 【支付宝存款】、【银联扫码】、【微信扫码】、【云闪付扫码】、【网银支付】<br />c：选择支付方式后提交订单，充值即可。</p>\n<p>温馨提示：使用银行卡转账时存款人姓名务必填写存款银行卡户主姓名</p>\n<h3>3.一定要开通网银才可以存款吗?</h3>\n<p>即使不开通也可以存款，通过支付宝或微信转账银行卡充值即可。如银行卡有开通网上银行功能可更方便进行存取款业务。</p>\n<h3>4.公司入款为什么经常更换账号?</h3>\n<p>为保证玩家的资金安全，亚新娱乐城的存款账号均为中国私人账号，与博彩公司无任何关系，并且会不定期更换不同账号供玩家存款。建议存款前点击线上存款选择对应的支付方式中获取最新的支付二维码或账号。</p>\n<h3>5.可以用别人的银行卡存款吗?</h3>\n<p>对于存款人是没有限制的，您可以使用自己或是朋友的银行卡进行转账，但是提款必须使用自己真实姓名的银行卡才能支付成功。</p>\n<h3>6.存款金额限制?</h3>\n<p>您账号使用任一支付方式单笔最低存款金额10元至无上限，大额存款建议分多笔提交。</p>', 2, 'zh_cn', 1, 0, 10, '2020-05-08 07:52:44', '2020-05-08 07:52:44'),
(22, '取款帮助', '', NULL, '<table>\n<tbody>\n<tr>\n<th>取款方式</th>\n<th>转账形式</th>\n<th>手续费</th>\n<th>到账时间</th>\n<th>交易限额</th>\n</tr>\n<tr>\n<td>人民币提款</td>\n<td>第三方支付平台支付到银行卡</td>\n<td>免费</td>\n<td>2小时内</td>\n<td>100RMB - 200000RMB,单日上限200万</td>\n</tr>\n<tr>\n<td>合作赌厅提款</td>\n<td>第三方支付平台支付到合作赌厅指定账户</td>\n<td>免费</td>\n<td>2小时内</td>\n<td>100RMB - 200000RMB,单日上限200万</td>\n</tr>\n</tbody>\n</table>\n<h3>1.取款金额限制?</h3>\n<p>大于等于￥100元(或等值其他货币)随时可以申请。当天取款金额为RMB100元 - RMB200万。</p>\n<h3>2.取款多久到账?</h3>\n<p>银行工作时间内（非周末的上班时间内），50万以内的提款可确保在2小时内到账；如果提款在下班后提出（9am-5pm 之外，以及周末时间），其中200万可以在2小时内支付，剩余部分会在第二天11点前完成支付。客服和彩金部门是24小时在线为您提供取款服务，星期一至星期日无休息。</p>\n<h3>3.取款有限制吗?</h3>\n<p>7*24小时不限次数可随时提款;客户存款后不论输赢，且在不享受开户优惠的前提下，有效投注额达到存款额度的1倍流水可随时提款。</p>\n<h3>4.信用卡可以取款吗?</h3>\n<p>我们强烈建议客户使用借记卡作为取款账户，由于银行限制问题，有些银行的信用卡支持收款，但支付到账时间不固定，有些信用卡不支持，为了避免耽误您收到款项的时间，建议您使用借记卡取款。</p>\n<h3>5.知道我账号密码的人可以提款吗?</h3>\n<p>收款人是没法更改的。别人要提款也只能提到绑定的银行账号上（也就是您的卡上）。首先为了防止账号遗失,请您把密码设置更复杂,同时请定时更换密码。并且我们对会员账号姓名与取款银行账号姓名进行了绑定,这样即使账号遗失,您的账号资金也是安全的。</p>\n<h3>6.取款如何取消?</h3>\n<p>若要取消提款请联系7*24客服为您取消提款申请。</p>\n<h3>7.什么是开户行网点?</h3>\n<p>您开户行网点指您的银行卡具体注册开户的地址或具体支行（例：辽宁省沈阳市红旗路支行）。账户性质：储蓄卡属借记卡性质；信用卡属贷记卡性质。开户行别是指您取款银行卡的银行名称。（例：中国工商银行）</p>\n<h3>8.为什么显示我只能取款一次?</h3>\n<p>每天提款的次数是不受任何限制的，如第一笔提款提案现在还在待审核中，没有为您付出，所以当您在提交第二笔后会出现这种提示：&ldquo;会员有未处理的取款提案&rdquo;，当您的第一笔取款审核后，是可以申请第二笔取款的。您可以在前一次取款成功后再次进行尝试或者可以将这笔款项取消，然后再与另一笔一起申请。</p>', 3, 'zh_cn', 1, 0, 10, '2020-05-08 07:53:48', '2020-05-08 07:53:48'),
(23, '规则与条款', '', NULL, '<p>此条款和细则应用于您在本网站、软件和服务的使用（ 用语&ldquo;条款和细则；网站、软件和服务&rdquo;定义如下）。如您不同意这此条款和细则，请不要继续使用本网站，如您继续使用本网站代表您接受并同意此条款和细则。此条款和细则是让您和我们之间形成一个具有法律效力的协议，您应当打印一份并妥善保管。如此条款和细则有变更，具体如下阐述。 用语&ldquo;您&rdquo;、&ldquo;您的&rdquo;&ldquo;我们&rdquo;、&ldquo;我们的&rdquo;以及其它词和短语定义如下列条款和细则中所示。这些用语连同我们的隐私政策和规则（统称&ldquo;条款和细则&rdquo;）是您和我们之间的最终协议。如与您使用本网站、软件、服务和其它协议（包括口头或书面协议）发生冲突，都以本条款和细则为准。</p>\n<h3>1.定义</h3>\n<p>1.1此条款和细则中一些词和短语有特定定义，此外，下列词和短语具有如下含义：</p>\n<p>&ldquo;账户限制&rdquo;是指玩家在账户进行设置，限制最高存款额度以及账户累积的合法赢利和奖金额度。</p>\n<p>&ldquo;投注&rdquo;是指在我们相关的服务产品，您或其它玩家的任何下注、赌注或类似的操作。</p>\n<p>&ldquo;设备&rdquo;是指任何应用于登录的装置，包括但不限于用于访问本网站和服务的个人电脑、笔记本电脑、手机、个人数码助理、PDA手机、手持设备。</p>\n<p>&ldquo;博彩&rdquo;是指任何类型的赌注、博彩、彩票或金融博彩。</p>\n<p>&ldquo;博彩软件&rdquo;是指能让您访问、连接和进入我们服务的任何软件、许可程序、数据文件或连接设备上的装置。</p>\n<p>&ldquo;信息&rdquo;具有下列5.1条款含义。</p>\n<p>&ldquo;合法盈利&rdquo;是指您在我们服务产品，严格遵从本条款和细则以正当、合法公平地赢得的资金。以下除外：(a)我们享有的佣金; (b)您使用本网站服务选择其它需要支付的费用; (c) 在相关的服务产品上，您使用的银行或其它金融提供商的退款。</p>\n<p>&ldquo;证可证&rdquo;具有下列条款11.3含义。</p>\n<p>&ldquo;会员申请&rdquo;具有下列条款7.1含义。</p>\n<p>&ldquo;我们的数据&rdquo;具有下列条款10.2含义。</p>\n<p>&ldquo;玩家&rdquo;是指本网站的所有用户，包括使用我们服务及同意本条款和细则的您。</p>\n<p>&ldquo;规则&rdquo;是指我们网站所列出为各种游戏产品提供的规则和服务，我们将会不定时更改。</p>\n<p>&ldquo;RNG&rdquo;( 随机数发生器）具有下列条款9.24的含义。</p>\n<p>&ldquo;服务&rdquo;是指本网站提供的博彩条款、产品和服务。</p>\n<p>&ldquo;软件&rdquo;是指任何本网站或组成网站的所有软件，包括博彩软件。</p>\n<p>&ldquo;网站&rdquo;是指 www.9170.com以及我们可能用于提供服务的其它网站。</p>\n<p>&ldquo;您&rdquo;、&ldquo;您的&rdquo;是指正使用本网站的您。</p>\n<p>&ldquo;您的账户&rdquo;具有下列条款7.11含义。</p>\n<p>1.2 为了言简意赅，本条款和细则提及的人称单数是也包括人称复数，同样的，人称代词他也包括她，身份称呼同样包括相关法规更改或重新更正以及二次立法更改后的称呼。</p>\n<h3>2.关于我们</h3>\n<p>2.1我们是在菲律宾合法注册。 2.2我们在菲律宾博彩监督委员监管下提供网站和服务条款 2.3如本条款和细则翻译成其它语言，都以中文版为准。 2.4如此条款和细则与其它文件不一致，都以本条款和细则为准。</p>\n<h3>3.注册</h3>\n<p>3.1在您注册时，代表您接受并同意：</p>\n<p>(a) 您已阅读、完全理解和接受网站条款和细则；</p>\n<p>(b) 使用我们的服务，此条款和细则在您和我们之间是具有法律效力的协议。</p>\n<p>3.2如您不同意网站条款和细则，请立即停止使用本网站。</p>\n<p>3.3您需接受及同意此条款和细则方可使用我们的服务。</p>\n<h3>4.修改</h3>\n<p>4.1我们拥有绝对权利随时更正、更新及修改此条款和细则以及规则，并且任何更改信息将在本网站上公布，一经公布将立即生效，请您定期查阅我们网站了解最新信息。您继续使用本网站和服务代表您接受及同意我们最新修改并发布的条款和细则以及规则。</p>\n<p>4.2我们未公布最新条款和细则前，任何投注将按网站当前所示的条款和细则确认注单。</p>\n<p>4.3您接受并同意您有责任查阅此条款和细则的任何修改及更新。</p>\n<h3>5.信息和知识产权</h3>\n<p>5.1网站上我们或我们许可方供您使用信息、资料和数据，包括但不限于营销计划、业绩和统计资料、体育数据和赛程表、赔率和投注数字、文字、图案、视频、音频内容以及我们的数据（用语&ldquo;我们的数据&rdquo;定义如条款10.2所示）这些信息和软件只供您个人使用，不作商业用途。</p>\n<p>5.2未经法律允许，您不得篡改、复制、修改、链接、仿制、存储、散布、展出、公开传播或有线传播，发布、传送、销售、出租、租赁、授予许可和为他人、 其它网站、网络服务 、公告栏、媒体或设备提供相关信息。</p>\n<p>5.3在网站或通过设备提供的软件、服务和信息是受版权、商标和其它形式的知识财产专有权保护的。网站的软件、服务和信息相关的所有权和利益归我们许可方所有、许可和监管。您接受并同意您不获取我们网站软件、服务和信息相关的所有权或利益，除非本条款和细则有明确注明。</p>\n<h3>6.使用条款</h3>\n<p>6.1作为服务使用条款，您同意并承诺您不会违反本条款和细则，使用或登录我们网站、服务和/或信息做任何违法行为。</p>\n<p>6.2除本条款和细则注明的所有明确条款外，您还同意和承诺下列服务使用条款：</p>\n<p>(a) 您的一切行为代表您自己，而非代表他人；</p>\n<p>(b) 您是受所有法律限制的；</p>\n<p>(c) 您不是被断定或归类为强迫性赌徒；</p>\n<p>(d) *您的年龄 (i) 年满18岁；或 (ii) 达到可以进行博彩的法定年龄；</p>\n<p>(e) 您充分了解博彩过程中、使用本网站和服务有输钱的风险；</p>\n<p>(f) 您账户的资金不是非法或未经授权的存款（用语&ldquo;您的账户&rdquo;定义如下列条款7所示）；</p>\n<p>(g) 您没有进行犯罪或其它非法、未授权行为，或企图使用您的账户进行该类行为，您不能使用或允许他人使用本服务和您的账户进行犯罪以及违法活动，包括但不限于洗钱和任何违反法律的活动；</p>\n<p>(h) 您会妥善保管您的用户名、账户号码和密码，以防他人被他人盗用；</p>\n<p>(i) 如您的账户、账户号码或密码有任何安全隐患，您将立即改您的密码并通知我们；</p>\n<p>(j) 无论承认或授权，您需要对所有通过您的用户名，账号和密码进行的所有活动负责；</p>\n<p>(k) 无论规则是否明确禁止，您不可使用服务，网站，装置，软件或信息，以任何方式干扰或可能干扰其他玩家，或作出任何试图对其他玩家不公平的优势的行为；</p>\n<p>(l) 您不可进行或试图协助任何第三方进行任何降低或可能降低服务和/或本网站的经营业绩的活动；</p>\n<p>(m) 您不会以任何方式招揽或寻求获得其他玩家的信息；</p>\n<p>(n) 您不会上传或散布任何会损坏或可能影响装置，软件，服务和/或网站程式的有病毒文件或数据；</p>\n<p>(o) 通过网站进入服务和信息没有被禁止 (i) 通过法律，对您或适用于你个人的合同义务；或， (ii) 通过法律，您身处国家的法律是适用于您使用装置进入本网站；</p>\n<p>(p) 如果您位于以下的地区，您将无法使用我们的网站：菲律宾，美国，柬埔寨</p>\n<p>我们和代表我们的第三方进行检查，以确定这些辖区内的玩家。 请注意，通过本网站进一步限制某些游戏产品可能适用于其他司法管辖区的玩家，在这种情况下，这些特定的游戏产品将被限制和/或禁止通过我们的网站访问;</p>\n<p>(q) 您不会与第三方串通，使用任何装置，机器人，设圈套，算法，软件或其他方法（或任何上述的性质）干扰或企图干扰服务，装置，软件，网站，通过本网站提供的信息或进行任何交易的运作；您进一步承认任何软件，赋予任何形式的不公平优势，在玩家之间共享漏洞卡（如果适用）或协助串通或欺骗任何方式，利用手的数据库（如适用）或播放器配置文件，减少或消除了对人作出决定的需要，被设计为&ldquo;数据集&rdquo;，提供关于在游戏期间采取的动作的实时建议（包括ICM分析工具），试图阻止我们的任何欺诈和作弊检测机制，将会被禁止的。我们将采取这样的步骤进行相应标识玩家机器上使用这种软件，以及您在此同意这一点，并不会与任何检测机制的干扰。 这些规则适用于所有情况。所有玩家必须代表自己和为自己的最佳利益。严禁代表雇主，血汗工场，&ldquo;金农场&rdquo;或任何形式的团队或合作社。严格禁止使用通过数据挖掘获得的任何数据，无论数据是由玩家自己还是由任何其他人获得的，以及与其他玩家共享任何合法收集的数据；</p>\n<p>(r) 您不会传播任何有非法，骚扰性，辱骂性，恐吓性，中伤，诽谤，淫秽，下流，激动，种族或民族反感，色情或亵渎的材料的内容信息，或任何可能构成或激发将被视为刑事罪行，引起民事责任的行为；</p>\n<p>(s) 您不是本公司或任何分支机构的官员，董事，雇员，顾问，组织成员，代理或上述的任何亲属；</p>\n<p>(t) 您不会阻碍服务，网站，软件，装置和/或信息的正确使用，或启动和/或参与调查，竞赛，连锁信，发送/转发的&ldquo;垃圾邮件&rdquo;，或大量邮件；</p>\n<p>(u) 您只会使用该服务于个人娱乐，您不得使用服务进行商业或谋生的一种方式；</p>\n<p>6.3你不能与另一个玩家一起合作来获得利益，不能对朋友&ldquo;软玩&rdquo;。 你不能进行&ldquo;筹码转储&rdquo;（即，他们不能故意失手或操纵游戏，以便转移资金到任何其他玩家。你不能与任何其他玩家共享漏洞卡信息，不得玩同一现金游戏或 所有这些禁止/限制都适用，无论是否使用本网站的各方之间有明确的协议，没有对他人造成任何实际的可证明的伤害。</p>\n<p>6.4如果您违反本条款和条件的义务，在我们的绝对酌情决定权下，我们可能会立即暂停或取消您的账户，并不另行通知。</p>\n<p>6.5如果您违反本条款和条款6中的任意一条的情况下，任何由您赢取的将是不合法奖金，因此无论是根据合同还是其他，我们没有义务支付该奖金给您。</p>\n<h3>7.开设您的账户</h3>\n<p>7.1为了使用服务，您必须依照网站上的指导填写账户和会员申请（以下简称&ldquo;会员注册&rdquo;）。</p>\n<p>7.2您保证，申请注册时提供的所有信息是准确，真实，完整的，包括您的姓名，资金来源（包括有关存款的详细信息，银行账户和信用卡号码）和地址。当登记和提款时，我们会使用内部方法和第三方的欺诈预防机构的专家为所提供的注册详细资料进行检查。</p>\n<p>7.3我们会采取合理和适当的措施，以确保您给我们的个人信息保持保密。除非任何适用的法律，法规，法院命令，有关博彩和执法部门或本条款及细则的要求，否則我们绝对不会透露您的个人资料或投注信息。</p>\n<p>7.4本公司保留将您的个人资料透露及转送到我们的支付结算服务提供商和金融机构支付服务的权利。该权利仅在必要时为履行服务而行使，并且将根据相关博彩或执法当局的适用法律和法规的要求。</p>\n<p>7.5我们会按照我们的隐私政策处理您的个人资料。</p>\n<p>7.6根据我们菲律宾牌照条款所管辖的玩家保护要求，玩家的资金（包括存款，奖金和适用的奖金）与经批准的银行持有，并根据菲律宾法律赋予特殊权力。根据菲律宾法律，在此客户账户中持有的任何钱被认为属于玩家。这意味着，如果破产，资金将首先偿还给玩家，在菲律宾博彩监督委员会的指导下。这种保护适用于我们的所有客户。</p>\n<p>7.7这是您的责任，确保您使用和进入的网站和信息，下载和安装软件和参与的服务并没有法律禁止。</p>\n<p>7.8我们可能不时需要您提供您的年龄和身份证明文件以作验证您的会员申请（如有效身份证件图片和确认的公用事业账单地址）。如果您的个人资料有任何更改，您必须立即通知我们有关变动。</p>\n<p>7.9我们保留通过邮寄或其他方式确认您的姓名和地址的权利。我们或许透过我们的判断，为您所提供的任何资料进行额外的安全检查。通过同意这些条款和条件，表示您让我们进入，使用，处理和存储任何身份验证或检查的结果。</p>\n<p>7.10我们有权不给予任何理由的情况下拒绝您的会员注册。</p>\n<p>7.11在我们接受您的会员注册前，您都不能使用该服务。</p>\n<p>7.12您需要以您的名义设立一个账户（&ldquo;您的账户&rdquo;），以使用和进入服务。</p>\n<p>7.13我们只允许每个人只有一个账户，家庭地址，电子邮件地址，电话号码，相同的付款方式和共享IP地址或设备（包括在图书馆，工作场所或网吧中公开的IP地址或设备）。如果我们发现或怀疑您有多个账户，我们保留自行决定的权利，将所有这些账户合为一个的账户，取消其他账户或终止您的账户。我们将在注册时使用内部数据库检查方法和第三方专家防欺诈机构检查重复注册详细信息。</p>\n<p>7.14您账户的货币是人民币。账户接受的最低存款为10元人民币。</p>\n<p>7.15在您的账户中持有的任何款项，我们为您保存在玩家的资金账户。然而，我们不是银行，我们不会在您的账户付任何的利息款项。</p>\n<h3>8.投注和接受投注程序</h3>\n<p>8.1我们接受所有在网站上的赌博游戏，体育博彩，金融博彩及其他项目的投注。所有投注必须遵守在我们博彩网站上所提供的每个游戏的条款和条件。</p>\n<p>8.2如本网站或在有关的任何投注或任何事件发生任何错误，并已投注，所有相关的投注即属无效。有关本网站的任何系统错误的情况下，我们保留因此类错误而导致的任何投注和/或任何收入损失的权利，包括但不限于：</p>\n<p>(a) 错误地接受在封闭/暂停市场上的投注；和</p>\n<p>(b) 投注结算/支付不正确。</p>\n<p>8.3透过我们的判断，本公司可在任何原因下保留拒绝全部，部分或任何在网站上投注的权利。我们保留在接受之前限制任何投注的权利。(我们网站不接受经系统判断后确认的单边投注和倍投，以及无风险投注方式)</p>\n<p>8.4我们只接受通过互联网和/或装置符合这些条款和条件的投注。我们不接受任何其他形式投注(不论通过邮寄，电子邮件，传真或以其他方式）没有按照这些条款和条件提交的任何投注会被撤销。</p>\n<p>8.5本公司有权推迟或拒绝任何我们怀疑对本网站或我们的操作系统有破坏能力的投注。</p>\n<p>8.6任何违反这些条款和条件的投注，将被取消及会在注册时提供的电子邮件地址以作通知。</p>\n<p>8.7不允许使用人工智能或软件（通常称为&ldquo;机器人&rdquo;），无论是商业获得的还是私人开发的。任何使用上述或试图使用上述的投注将被取消，相应的账户将被关闭。您不会与第三方串通，使用任何设备，机器人，蜘蛛，算法，软件，例程或其他方法（或上述任何内容）干扰或试图干扰服务，设备，软件，网站，信息或通过网站提供的任何交易。您进一步承认任何软件，赋予任何形式的不公平优势，在玩家之间共享漏洞卡（如果适用）或协助串通或任何欺骗任何，利用手机数据库（如适用）或播放器配置文件，减少或消除了对人作出决策的需要，被设计为&ldquo;数据挖掘&rdquo;，提供关于在玩游戏期间采取的动作的实时建议（包括ICM分析工具），试图阻止我们的欺诈和作弊检测机制，被禁止。我们将采取这样的步骤，以相应地确定这样的软件在播放器机器上的使用，您特此同意这一点，不会干扰任何检测机制。这些规则适用于所有情况。</p>\n<p>8.8投注只会有效于正确的用户名和密码和账户中有足够的余额。</p>\n<p>8.9您需对您账户内的使用，活动和交易负责（无论使用，活动或交易是否由您获授）：</p>\n<p>(a) 您的姓名；和/或，</p>\n<p>(b) 您的账户号码； 和/或，</p>\n<p>(c) 您的用户名和密码。</p>\n<p>8.10 您有责任确保您所下注细节是正确的。一旦系统接收您的投注（成功下注），您将不能取消，撤销或更改您的投注。</p>\n<p>8.11 所有投注记录，都会记录我们的交易记录数据库。我们的交易记录数据是有关您和/或任何玩家所投注确凿的交易证据。</p>\n<p>8.12 当在您的账户显示交易确认和您的交易记录已更新，投注才被视为有效及接受。</p>\n<p>8.13 在任何投注开始后或结果是已知的位置的时候，您不可再下注。如上述事件发生后，而您下了注，我们保留拒绝支付或作废的权利。</p>\n<p>8.14 接受任何投注要求或其任何部分将由我们自行决定，我们保留在接受之前限制任何投注的权利。为免生疑问，这条8.14条款不禁止如我们所提供的&ldquo;开始&rdquo;或&ldquo;半时&rdquo;投注。</p>\n<p>8.15 在网站上通告上显示的开始下注时间，仅供参考之用。如果由于某种原因，我们的游戏，赛事，项目或比赛开始后仍然接受投注，我们保留取消的权利。</p>\n<p>8.16 除非另有说明，否则在规则之内的体育或事件，比赛结果，赛事，项目或比赛结果将决定其结束之日。任何随后疑问，可能会导致相关游戏，赛事，项目或比赛的推翻决定，我们将不会认可，及保留原来的结算。</p>\n<p>8.17 如果体育赛事的场地改变，所有投注在原场地的投注，将是无效的。</p>\n<p>8.18 我们不承认暂停的游戏，竞赛，活动或比赛或反对或推翻在相同的决定。</p>\n<p>8.19 如果您在多个投注无效选择，剩余的有效选择（如果有的话）投注进行结算。</p>\n<p>8.20 您确认任何和所有的赔率和盘口如有变动，恕不另行通知，前述的只固定于在我们接受相关投注的时间。</p>\n<p>8.21 当系统发生故障，任何类型赔率和盘口结果不正确，所有投注都将无效。当错误时纠正时，我们可能会使用酌情权（但非必须）允许您选择另一个正确赔率和盘口投注。</p>\n<p>8.22 我们不会接受您在任何一场比赛，赛事，事件同时下注。</p>\n<p>8.23 在任何投注与之相关的交易，我们的决定是最终及不可推翻的。</p>\n<p>8.24 您确认，洗牌和分牌，转球，摇动骰子游戏的结果，彩票和其他随机生成的结果取决于随机数发生器（RNG）或网站上提供的现场游戏，是服务的一部分，您同意接受这样的洗牌和分牌， 转球，摇动骰子，所进行的游戏，彩票和其他随机生成或现场的结果是最终及不可推翻的。</p>\n<h3>9.您账户的交易和交收</h3>\n<p>9.1 当使用信用卡或提款卡，持卡人的姓名必须与会员申请提供的名称相同。持卡人的姓名和有关会员申提供的名称之间差异的情况下，我们保留拒绝交易的权利。</p>\n<p>9.2 根据法律规定，您有责任支付您与本公司或本公司有关的任何及所有债务。您同意，您不会故意取消，拒绝或撤销任何投注，及您将会向我们支付所有因取消，拒绝或撤销造成的任何及所有损失。</p>\n<p>9.3 如果我们怀疑您从事任何欺诈或滥用奖励的活动，我们有权终止您的参与，和/或拒绝您的提款要求。</p>\n<p>9.4 您的合法奖金，不包括有关的投注，活动或游戏产生的合法奖金。</p>\n<p>9.5 我们不会因支付过程所发生的任何错误负责。我们有权保留任何因支付过程错中误导致的有关投注或交易取消的权利。如果您发现您账户的余额不匹配，您必须尽快通知我们。</p>\n<p>9.6根据法律，您有责任支付合法奖金的任何税项、费用或收费。</p>\n<p>9.7如果存入您账户的款项是错误的，当您意识到错误时，在任何情况下，您有责任尽快通知我们。任何因错误而存入到您的账户的款项将被视为无效，在事件中， 如您的账户有足够的款项，这些款项会立即从您的账户中归还给我们。但如果您的账户沒有足够的款项，您亦应立即将相等的金额归还给我们。错误存入在您账户的款项不可用作投注。 本公司有权保留取消因错误支付的涉及款项而用作任何交易和/或投注的权利。 为免生疑问，如您账户里还有余额和错误款项，您仍然可以使用您账户里拥有的余额进行交易和/或投注。</p>\n<p>9.8 您在此同意，保证及声明，在经本公司同意下，您不会将账户的存款扣款，取消或宣告放棄。任何上述发生的情况下，您同意对我们赔偿由此引起的任何费用，索赔，损失和费用，并退还， 赔偿我们的任何损失，否则，我们将承担所产生的此类行动，包括我们在这个过程中收回该等款项所产生的任何费用。</p>\n<p>9.9我们保留随时根据适用的法律和法规对您账户上的任何活动（包括但不限于以下）进行任何及所有身份，信用和其他验证检查的权利：根据适用法律或法规为您的账户存款设定的最低限额）。您同意提供我们在进行此类验证检查时需要的所有信息。我们保留暂停/限制您的账户和取钱的权利，除非验证顺利进行。</p>\n<h3>10.合法盈利的收集</h3>\n<p>10.1 合法盈利将会存入您的账户。如要求从您的账户提款，您可能会被要求出示或以其他方式提供我们求出的必须调查文件。这通常是个人身份证明文件的副本（如护照，身份证或驾驶执照） 及确认您的地址证明文件（如水电费账单）。我们可能需要您其他文件的副本，以打击欺诈和/或清洗黑钱活动。</p>\n<p>10.2 如从您的账户在三十（30）天的期限，一次性或累计提取超过二万二千五百元人民币，您必须出示有效的身份证明文件。根据条款10.10，我们保留随时根据适用的法律和法规要求和/或要求对您的任何活动进行任何和所有进一步的身份识别，信用和其他验证检查的权利账户。</p>\n<p>10.3您的发卡银行允许的话，您的合法盈利将存入您的信用卡，提款卡。接收合法盈利必须是与存入资金及投注者是同一个人。</p>\n<p>10.4任何个人或团体涉嫌欺诈行为，我们有权取消全部或部份的相关投注。同时，我们也有权扣除相关的账户资金。</p>\n<h3>11.优惠和奖金</h3>\n<p>11.1所有优惠，奖金或特别优惠都受这些条款和条件管制，此外，除了优惠的具体条款和条件管制外，我们可能会不时与其一同介绍。我们保留暂停，取消或修改奖金或优惠规则的权利。</p>\n<p>11.2 如我们在任何情况下怀疑您或任何其他玩家滥用或企图滥用奖金或其他推广活动（或从中得到利益），我们可能会阻止，拒绝，暂停，中止或取消任何这些玩家的账户。</p>\n<p>11.3除非在明确的优惠，奖金或特别优惠的条款和条件中特别说明，否则优惠，奖金和特别优惠仅限于每位客户在7天的滚动期内。</p>\n<p>11.4我们自行决定，所有优惠，奖金或特别优惠以及使用根据条款8.14中定义的可疑重复账户获得的此类优惠所产生的任何盈利将被取消，同时您的账户将被关闭。</p>\n<p>11.5如果我们怀疑，根据我们的绝对酌情决定权，您正在滥用或企图滥用奖金或优惠，我们可能会暂停或关闭您的账户，并保留预扣任何相关盈利的权利。此类滥用应包括但不限于：（i）不规则投注模式，以满足投注要求或规避系统优先级；（ii）使用多个账户;（iii）低风险投注（例如为了保证利润而不考虑结果）。</p>\n<p>11.6如果奖金在第一次提取之日起六个月内未达到投注额要求（除非在奖金特定条款和条件中另有规定），奖金将被取消并从账户中扣除。</p>\n<h3>12.您给我们的赔款</h3>\n<p>12.1如以任何方式所产生的疏忽作为，下载或安装本软件，使用的软件和/或信息，和/或违反这些条款和条件的任何部分，您在此赔偿我们，我们的员工任何及所有成本，费用，损失，损害或索偿（包括合理的律师费）。</p>\n<h3>13.免责声明及服务的性质</h3>\n<p>13.1博彩是您自己的选择和判断。你应该知道及承担使用本服务所带来的全部风险。当您使用这服务时，您确认您沒有判断这服务，网站或信息有任何攻击，令人反感，不公平或不雅的。 某些司法管辖区没有解决在网上博彩的合法性，而另一些专门令到网上博彩是非法的。我们无意使任何网上博彩是非法的司法管辖区内的人使用服务或进入网站。 在上述的任何司法管辖区中，我们的服务，网站和信息的可用性不应被理解为提供，招揽或邀请。遵守任何适用于您的服务，网站或信息法律服完全是您自己的责任， 我们不会对这作任何声明或保证。</p>\n<p>13.2我们将竭力使用合理的技能和关注服务，网站，软件和信息，但不能保证我们会对任何服务，网站，软件和信息作任何声明或保证。在超出法律最大范围的允许上，不论是明示或默示， 法定或其他方面的服务，软件，网站和信息均予排除。</p>\n<p>13.3本网站和软件都提供了&ldquo;似乎&rdquo;。我们不保证服务，软件，网站或信息是准确，完整，适合，及时，安全，无中断，无缺陷，无错误或不受任何性质的外界干扰或任何不明的缺陷将得到纠正。</p>\n<p>13.4我们不保证的服务、软件、网站、信息或服务器是沒有电脑病毒、漏洞、间谍软件、广告软件或其他恶意、破坏性或损坏的代码、程式、数据或任何其他功能任何可能，可能会影响装置和/或包含的数据。您将承担您自己的预防措施（自费）确保使用服务软件的过程，措施和/或装置不摆出病毒，破坏性或损坏或其他形式的干扰的风险。</p>\n<p>13.5在事件中，如：</p>\n<p>(a) 您账户的系统和/或相关的通信有任何的延误，本网站或本服务的任何其他元素和/或，</p>\n<p>(b) 您账户的系统和/或相关的通信有任何的错误，本网站或本服务的任何其他元素和/或；</p>\n<p>我们将不对延误和/或错误情况下的结果负任何责任，如因在延误和/或错误的情况下下注，我们有权保留所有投注无效的权利，和采取任何我们认为适当的行动来纠正这种延误或错误。</p>\n<p>13.6在任何情况下，我们都不会为任何损害，损失或开支负责或承担责任，包括任何装置或数据的干扰或损坏，进入使用的连接，使用或参与服务，网站，软件和/或信息。</p>\n<p>13.7我们不承担任何及所有由第三方提供的服务，网站，软件和信息的责任，包括但不限于宽频服务供应商，电信供应商，银行和支付供应商，和第三方不得对任何账户承担任何违约或违反的责任。</p>\n<p>13.8我们，我们的员工和代理人将不会对合同形成时不可预见的任何损失，合同，侵权，疏忽或其他方面的损失负责，这些损失不是由于我们的任何违约，业务损失或由与服务，网站，软件或信息有关的任何用户，包括但不限于对业务损失，数据丢失，利润或合同损失，收入或收入损失，数据丢失或商誉损失的任何损害。</p>\n<p>13.9我们特此排除所有您的责任，无论是在合同的侵权行为，疏忽或其他。</p>\n<p>13.10我们不排除因我们因欺诈或欺诈性失实陈述或对基本问题的虚假陈述而导致的疏忽或责任造成的死亡或人身伤害的责任，以及我们在为您提供服务时未能使用合理技能和谨慎。您的法定权利不受影响。</p>\n<p>13.11您确认部分或全部的信息可能是临时性的，而这些条款和条件的规定可能会受到修订，变更或修改。因此，您确认，所提供的资料仅用于参考，并不构成建议或招揽，及不构成对任何保证，合同义务，依赖于你的任何性质具约束力。</p>\n<p>13.12我们对您的整个的条款，合同，侵权，疏忽或以其他方式的总责任，在任何情况下不得小于：</p>\n<p>(a) 有关事件引起的索赔款项，总额相等于您在之前六（6）个月，账户里存款和下注； 或，</p>\n<p>(b) 总金额为五万元人民币。</p>\n<p>13.13您确认并同意，所有在这些条款和条件的免责声明和责任，代表您与我们之间的协议的风险和收益分配是公平和合理的，考虑所有相关因素在内，包括但不限于您提供给我们。</p>\n<p>13.14除载列于本条款及条条件，如果您对我们进行任何赌博的结果有任何争议，您必须向我们提交书面投诉，包括在有关结果发出一个自然月内及完整的细节。如果交易的结果出现在您的装置和我们的系统中之间有差异的情况下， 您同意，证明我们系统的交易记录由我们的首席技术总监确凿。</p>\n<h3>14.终止，关闭和暂停服务</h3>\n<p>14.1由于服务的性质，如果您违反本条款和条件下的任何义务，我们保留随时终止您的账户的权利，恕不另行通知。在关闭您的账户之前，您将会通过电子邮件收到关于我们决定终止您的账户的通知，任何合法的盈利和您账户中的其他合法款项，将被退还到您的账户。在此期间，您的账户将被暂停，您将无法进行投注。</p>\n<p>14.2除了根据这些条款和条件的权利，在我们的判断下，我们保留其他的权利：</p>\n<p>(i) 取消任何奖金（包括合法的奖金）； (ii) 暂停或终止您的账户； (iii）与您终止这些条款和条件；和/或暂停为您提供服务，如我们确定：</p>\n<p>(a) 您企图用同地址下多个账户申请优惠；</p>\n<p>(b) 您提供给我们的名称与您的提款卡上的名字不匹配；</p>\n<p>(c) 您参与我们所提供的推广优惠，但未能履行有关的推广的要求；</p>\n<p>(d) 您登记时提供的资料不正确或具误导性；</p>\n<p>(e) 没有提供我们要求的个人身份证明文件；</p>\n<p>(f) 你是不是18岁以上或沒达到在您所在的司法管辖区参与博彩的法定年龄；</p>\n<p>(g) 在您的您司法管辖区内禁止博彩，而您参与这些服务，或者我们认为（合理），这种参与是法律所禁止的；</p>\n<p>(h) 您对我们拒绝您账户的任何交易或存款&ldquo;扣款&rdquo;；</p>\n<p>(i) 从刑事或其他非法或未经授权的活动试图把资金存入或已存入您的账户；</p>\n<p>(j) 您有作弊或企图作弊；</p>\n<p>(k) 你企图进行欺诈；</p>\n<p>(l) 您雇用或寻求使用人工智能或其他系统 （包括机械，电脑，算法，软件或其他自动化系统）击败我们所运营的系统，或您企图与其他玩家串通或勾结，以骗取我们（或其他玩家）。</p>\n<p>(m) 您（有意或无意）允许第三方使用您的账户；</p>\n<p>(n) 您不遵守这些条款和条件的任何规定；</p>\n<p>(o) 您试图隐瞒你所居住的地方的司法管辖权；</p>\n<p>(p) 您位于第6.2（q）条定义的限制区域。</p>\n<p>14.3如果服务暂停和/或您的账户被停用，服务可能会恢复和/或您的账户可能被重新激活必要的整改后，我们已采取必要的整治行动，（如果能够纠正） 账户的整改已经得到了验证，您的账户可以被重新激活。</p>\n<h3>15.链接到外部网站</h3>\n<p>15.1本网站可能包含不在我们维修范围的第三方网站链接。这样的第三方网站的链接仅是为您提供方便，我们是不负责，不承担及确保这些第三方网站的内容是准确，通用或维修。</p>\n<p>15.2我们不承担任何责任，也没有提供，审核，批准或认可任何第三方网站，及我们不会为三方网站的内容，隐私，或出售或以其他方式提供的任何产品和服务作任何陈述或保证。</p>\n<p>15.3我们不会为因您以任何方式与第三方网站的链接所产生的任何损失或损害，如合同，侵权，疏忽，或以其他方式承担责任。</p>\n<p>15.4除非另有明文规定，我们在任何情况下都不应与第三方网站被视为相关或隶属，或与第三方网站的经营者或所有者，如任何声明，意见，出售或以其他方式提供的任何产品或服，或与第三方网站的经营者或所有者。</p>\n<h3>16.网站链接</h3>\n<p>16.1您不可链接或创建任何链接到网站，服务或信息架构的任何部分。</p>\n<h3>17.&ldquo;服务&rdquo;添加/或删除</h3>\n<p>17.1本公司保留在任何时候在网站上添加新的博彩产品，游戏或功能的权利，或创建，删除，停止，限制进入或修改; 或修改任何博彩产品，游戏或功能，恕不另行通知。</p>\n<h3>18.被遗弃的账户</h3>\n<p>18.1 如果您连续三百六十五（365）天沒有登录您的账户和使用本网站的服务，您的账户将被视为非活动状态。</p>\n<h3>19.账户限额，支付限额和最大赌注</h3>\n<p>19.1在每注有效的投注里，我们支付予玩家的最高限额为一百万元人民币。</p>\n<p>19.2下注的最高金额是根据不同类型的游戏或博彩，您可以下注最高金额，我们有提供有关类型的博彩规则，和/或本网站的条款如有变更，恕不另行通知，但在任何情况下，您的注额将不超过账户里的资金。</p>\n<h3>20.违反这些条款和条件</h3>\n<p>20.1如有任何违反这些条款和条件，我们有权寻求法律和公平的补救措施。</p>\n<h3>21.不可抗力</h3>\n<p>21.1如果我们因非我们所能控制的事件发生，而不能或迟了履行这些条款和条件下的任何义务（包括但不限于：自然灾害、法律或规例的变化、政府的行动或非行动、民事或军事机关、 法院命令、恐怖主义行为、闪电或火灾、罢工、停工或其他劳资纠纷、洪水、干旱、战争、暴乱、盗窃、传输或系统故障、电信或宽带服务故障或中断提供、故障或电源供应器设备不足、天气恶劣、地震和自然灾害），这样的疏忽或拖延并不构成违反这些条款和条件。</p>\n<h3>22.非豁免</h3>\n<p>22.1在事件中，如果我们未能执行这些条款和条件的任何规定，这不会对此类规定或影响这些条款和条件的有效性或妨碍我们任何进一步行动呈现豁免的权利。</p>\n<h3>23.您和我们之间的关系</h3>\n<p>23.1在这些条款和条件中的任何内容均不解释我们和您之间为任何代理，合作火伴，合资或任何其他形式的合资企业。</p>\n<h3>24.分割</h3>\n<p>24.1如果这些条款和条件的任何部分被有管辖权的法院确定为无效，非法或不可执行，这些条款将被从其他分开，而其它的将继续在法律所允许的最大范围内，以有效和可强制的方式执行。</p>\n<h3>25.终止</h3>\n<p>25.1条款第2.3、5、13、14、19、22、29和31在终止您的账户后应延长这些条款和条件。</p>\n<h3>26.第三方权利</h3>\n<p>26.1这些条款和条件中的任何内容，无论是根据法例或其他，除了您和我们之间，第三方都不会造成或赋予任何权利或利益。</p>\n<h3>27.转送</h3>\n<p>27.1您不得向任何第三方转送，分配或更新这些条款和条件的任何部分。</p>\n<p>27.2我们有权在任何时候向任何第三方转送，分配或更新这些条款和条件的任何部分。</p>\n<h3>28.通知</h3>\n<p>28.1我们提供给您的任何通知（除非另有说明，这些条款和条件）将被发送到在您注册时所提供的电子邮件地址。任何这样的通知，由派遣后的二十四（24）小时将被视为已送达。</p>', 6, 'zh_cn', 1, 0, 10, '2020-05-08 07:58:13', '2021-05-18 05:06:28'),
(24, '合作伙伴', '', NULL, '<h3>代理合作A模式（日结）：</h3>\n<p>佣金日结，存款返佣+流水返佣的双重回报</p>\n<table>\n<tbody>\n<tr>\n<td>当日最低活跃会员</td>\n<td>存款返佣比例</td>\n<td>流水返佣比例</td>\n<td>彩票流水返佣比例</td>\n<td>佣金派送时间&amp;形式</td>\n</tr>\n<tr>\n<td>3人</td>\n<td rowspan="3">0.5%</td>\n<td>0.4%</td>\n<td>0.2%</td>\n<td rowspan="3">\n<p>每天18:00系统自动发放前一日佣金，可直接提款</p>\n</td>\n</tr>\n<tr>\n<td>4 - 9人</td>\n<td>0.5%</td>\n<td>0.3%</td>\n</tr>\n<tr>\n<td>10人及以上</td>\n<td>0.6%</td>\n<td>0.4%</td>\n</tr>\n</tbody>\n</table>\n<ol>\n<li><span ng-click="selectedUnion = 3;">注册代理</span> - 联系代理专员 - 开通代理账户，简单三步赚取佣金，开始成就梦想之旅</li>\n<li>有效活跃会员定义：当日至少3人都存款&ge;300元，且有效打码量都&ge;300元之会员</li>\n<li>若当日不满足有效活跃会员条件，则当日代理佣金将累计到符合日结代理条件一并派发。</li>\n</ol>\n<h3>日结佣金计算举例：</h3>\n<p>某代理于当日12:00至次日11:59，代理线下有8位活跃会员，所有会员的总存款金额为100万，总打码量为300万；</p>\n<p>彩票会员可获得100万x0.5%+300万x0.3%=实发佣金14000元；</p>\n<p>非彩票会员可获得100万x0.5%+300万x0.5%=实发佣金20000元；</p>\n<h3>代理合作B模式（月结）：</h3>\n<table>\n<tbody>\n<tr>\n<th>当月净盈利</th>\n<th>当月最低有效活跃会员</th>\n<th>当月返佣比例</th>\n</tr>\n<tr>\n<td>100~100000</td>\n<td>5或以上</td>\n<td>30%</td>\n</tr>\n<tr>\n<td>100001~500000</td>\n<td>20或以上</td>\n<td>35%</td>\n</tr>\n<tr>\n<td>500001~1000000</td>\n<td>60或以上</td>\n<td>40%</td>\n</tr>\n<tr>\n<td>1000001~2000000</td>\n<td>100或以上</td>\n<td>45%</td>\n</tr>\n<tr>\n<td>2000001以上</td>\n<td>200或以上</td>\n<td>50%</td>\n</tr>\n</tbody>\n</table>\n<ol>\n<li>佣金月结，以当月代理线下所有会员总负盈利的返佣比例结算；<br />每月5号统一派发上一月佣金。</li>\n<li>有效活跃会员定义：当月至少5人都存款&ge;500元，且有效打码量都&ge;500元之会员</li>\n<li>若当月不满足有效活跃会员条件，则当月代理佣金将累计到符合月结代理条件一并派发。</li>\n</ol>\n<h3>月结佣金计算方式及说明：</h3>\n<p>某代理当月内，该线下至少有5位有效活跃会员方可结算返佣；</p>\n<p>举例说明：代理佣金比例为30%</p>\n<p>代理佣金=（平台损益-优惠-返水-行政费用）*30%</p>\n<p>代理平台费=平台损益*10%*30%</p>\n<p>实发代理佣金=代理佣金-代理平台费</p>\n<p>代理客服服务</p>\n<p>代理QQ：2304666568、1712649090</p>\n<p>代理邮箱：9170jscom@gmail.com</p>\n<p>代理客服工作时间：12:00-22:00</p>\n<p>亚新娱乐9170.com期待一切有胆量、有才略、有远见的有识之士加入我们的同富共荣圈。</p>\n<p>注：本项目的最终解释权及更改权归9170亚新娱乐所有！</p>', 5, 'zh_cn', 1, 0, 10, '2020-05-08 08:03:59', '2020-05-08 08:03:59'),
(25, '营联协议', '', NULL, '<p>&ldquo;亚新娱乐&rdquo;与BBIN进行技术合作，为哥斯特黎加合法注册之博彩公司。我们采用最为多元、 先进、公正的系统，在众多博彩网站中，我们自豪能为会员提供最优惠的回馈、为代理商创造强劲的营利优势! &ldquo;亚新娱乐&rdquo;秉持商业联营、资源整合、利益共享的理念，与合作伙伴携手打造利多的荣景。 无论您拥有的是网络资源，或是丰富的人脉，都欢迎您来加入我们的行列，不须负担任何费用， 就可以开拓无上限的营收。&ldquo;亚新娱乐&rdquo;娱乐绝对是您最聪明的选择!</p>\n<h3>一、代理商注册规约</h3>\n<p>为防堵不肖业者滥用&ldquo;亚新娱乐&rdquo;所提供的代理优惠制度，我们将严格审核每位代理商申请注册时所提供的个人资料(包括 姓名、IP、住址、电邮信箱、电话、支付方式等等)。若经审核发现代理商有任何不良营利企图，或与其他代理 商、会员进行合谋套利等行为，&ldquo;亚新娱乐&rdquo;娱乐公司将关闭该合作代理商之账户、扣除账户中的本金，并收回该代理商 的所有佣金与优惠。 同一IP/同一姓名/同一收款账号的会员只能是一个合作代理商的下线，代理商本身不能成为其他代理商的下线会员。</p>\n<h3>二、权责条款</h3>\n<h4>2.1、&ldquo;亚新娱乐&rdquo;对联盟伙伴的权利与义务</h4>\n<p>&ldquo;亚新娱乐&rdquo;的客服部门会登记合作代理商的下线会员并观察其投注状况。 代理商及会员皆须同意并遵守&ldquo;亚新娱乐&rdquo;的会员条例、政策及操作程序。 合作代理商可随时登入管理端接口观察其下线会员的下注状况与活动概况。 &rdquo;亚新娱乐&rdquo;保留所有对合作代理商或会员之账户加以拒绝或冻结的权利。 &ldquo;亚新娱乐&rdquo;有权修改合约书上之任何条例(包括:现有的佣金范围、佣金计划、付款程序、及参考计划条例等 等)，&ldquo;亚新娱乐&rdquo;公司会以电邮、网站公告等方法通知合作代理商。若代理商对于任何修改持有异议，可选择终止合 约、或洽客服人员提出意见。如代理商未提出异议，便视作默认合约修改，必须遵守更改后的相关规定。</p>\n<h4>2.2、联盟伙伴对&ldquo;亚新娱乐&rdquo;的权力及义务</h4>\n<p>合作代理商应尽其所能，广泛地宣传、销售及推广&ldquo;亚新娱乐&rdquo;使代理商本身及&ldquo;亚新娱乐&rdquo;的利润最大化。合作 代理商可在不违反法律的情况下，以正面形象宣传、销售及推广&ldquo;亚新娱乐&rdquo;， 并有责任义务告知旗下会员所有关于&ldquo;亚新娱乐&rdquo;的相关优惠条件及产品。 合作代理商选择推广&ldquo;亚新娱乐&rdquo;的手法若需付费，则代理商应自行承担该费用。 任何&ldquo;亚新娱乐&rdquo;的相关信息(包括：标志、报表、游戏画面、图样、文案等)，合作代理商不得私自复制、公开、 分发有关材料，&ldquo;亚新娱乐&rdquo;保留法律追诉权。 如代理商在业务推广方面需要相关的技术支持， 欢迎随时洽询&ldquo;亚新娱乐&rdquo;客服人员。</p>\n<h4>2.3、各项细则</h4>\n<p>各阶层合作代理商不可在未经&rdquo;亚新娱乐&rdquo;娱乐允许下开设双/多个代理账号， 也不可从&ldquo;亚新娱乐&rdquo;之游戏账户或其他相关人士赚取佣金。 请谨记任何代理商皆不能用代理账户下注，&ldquo;亚新娱乐&rdquo; 有权终止并封存账号及其所有在游戏中赚取的佣金。</p>\n<p>为确保所有&ldquo;亚新娱乐&rdquo;会员的账号隐私与权益，&ldquo;亚新娱乐&rdquo;不会提供任何会员密码，或会员个人资料。 各阶层合作代理商亦不得以任何方式取得会员数据，或任意登入下层会员账号， 如发现代理商有侵害&ldquo;亚新娱乐&rdquo;会员隐私的行为，&ldquo;亚新娱乐&rdquo;有权取消代理商之红利，并取消该名代理商之账号。</p>\n<p>合作代理商旗下的会员不得开设多于一个的账户。&ldquo;亚新娱乐&rdquo;有权要求会员提供有效的身份证明以验证会员的身份， 并保留以IP判定会员是否重复注册的权利。如违反上述事项，&ldquo;亚新娱乐&rdquo;有权终止玩家进行游戏并封存账号及所有于游戏中赚取的佣金。</p>\n<p>如合作代理商旗下的会员因违反条例而被禁止使用&ldquo;亚新娱乐&rdquo;的游戏， 或&ldquo;亚新娱乐&rdquo;退回存款给会员，&ldquo;亚新娱乐&rdquo;将不会分配相应的佣金给代理商。 如合作代理商旗下会员存款用的信用卡、银行资料须经审核，&ldquo;亚新娱乐&rdquo;将保留相关佣金直至审核完毕。</p>\n<p>合约条件将于&ldquo;亚新娱乐&rdquo;正式接受合作代理商加入后开始生效。 &ldquo;亚新娱乐&rdquo;娱乐公司及代理商可随时终止此合约。 在任何情况下，代理商若欲终止合约，都必须以书面/电邮方式提早于七日内通知&ldquo;亚新娱乐&rdquo;。 代理商的表现将会每3个月审核一次，如代理商已不是现有的合作成员，则本合约书可以在任何时间终止。 如代理商违反合约条例，&ldquo;亚新娱乐&rdquo;有权立即终止合约。</p>\n<p>在没有&ldquo;亚新娱乐&rdquo;的许可下， 代理商不能透露及授权&ldquo;亚新娱乐&rdquo;的相关机密资料， 包括代理商所获得的回馈、佣金报表、计算方式等；代理商有义务在合约终止后仍执行机密文件及数据的保密。 合约终止之后，代理商及&ldquo;亚新娱乐&rdquo;将不须履行双方的权利及义务。 终止合约并不会解除代理商于终止合约前所应履行的义务。</p>', 5, 'zh_cn', 1, 0, 10, '2020-05-08 08:05:11', '2021-05-12 14:49:29'),
(26, '联络我们', '', NULL, '<p>亚新娱乐 www.9170.com 全天候24小时为您提供多种贴心的联络方式。 当您有任何疑问、意见都可以通过下述方式随时与我们联系，我们将竭诚为您服务。<br />如果您对本网站的使用有任何疑问，可以透过下列任一方式与客服人员联系，享受最实时的服务：</p>\n<p>通过网站24小时在线客服：点击【在线客服】进行咨询，享受最实时的服务。</p>\n<ol>\n<li>客服QQ：97889170</li>\n<li>代理QQ：2304666568</li>\n<li>客服邮箱：jskf9170@gmail.com</li>\n<li>投诉邮箱：jscom9170@gmail.com</li>\n</ol>', 7, 'vi', 1, 0, 10, '2020-05-08 08:07:38', '2021-05-12 14:13:04'),
