INSERT INTO `activities` (`id`, `title`, `subtitle`, `cover_image`, `content`, `type`, `apply_type`, `apply_url`, `apply_desc`, `hall_image`, `hall_field`, `start_at`, `end_at`, `date_desc`, `is_open`, `is_hot`, `is_app`, `lang`, `rule_content`, `weight`, `created_at`, `updated_at`) VALUES
(1, '新会员首存', '', 'https://api.xxxx.com/storage/uploads/activity/202004/24/activity_1587735370_drWjCzHVyo.png', '<p><img src="https://api.xxxx.com/storage/uploads/editor/202004/24/editor_1587735447_1LFgyjRXAz.png" alt="" width="750" height="194" /></p>\n<p>例：会员首次存款888，即可申请获得128元奖金。</p>\n<p>流水计算方式：（本金 奖金）*流水倍数</p>', 3, 2, '', '', 'https://api.xxxx.com/storage/uploads/activity/202004/24/activity_1587736138_dYCw0dMZoc.png', 'member_name,recharge_money', NULL, NULL, '即日起', 1, 1, 0, 'zh_cn', '', 12, '2020-04-24 13:42:09', '2025-05-31 08:53:20'),
(2, '公司入款比比赠送', '', 'https://api.xxxx.com/storage/uploads/activity/202004/24/activity_1587736395_BpitTZC9bi.png', '<p><img src=https://api.xxxx.com/storage/uploads/editor/202004/24/editor_1587736472_zuGT7du4w8.png" alt="" width="750" height="130" /></p>\n<p><img src=https://api.xxxx.com/storage/uploads/editor/202004/24/editor_1587736481_4EdCuYJbtO.png" alt="" width="750" height="188" /></p>', 4, 0, '', '<p>会员无需提交申请，完成指定优惠入款方式后，系统将自动派发到会员账户。</p>', '', '', NULL, NULL, '即日起', 1, 0, 0, 'zh_cn', '<p><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>1.本活动以北京时间为计时区间，所获奖金 本金达到10倍流水即可申请提款；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>2.每位会员每日仅限申请一次；会员请在成功存款后，未进行任何投注前，前往<a href="https://9170pay.com/Activity" target="_blank" rel="noopener"><span style="color: #f39c12;">【优惠大厅】</span></a>提交申请；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>3.若会员存款后进行投注，则取消参与本活动资格；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>4.所有参与本活动的会员，不得同时参与其他存送活动；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>5.本活动仅限投注于真人视讯，其余游戏不得参与此优惠活动；单笔投注金额不得超过（本金 奖金）总额的70%；<br />6.所有参与本活动的会员，即表示您已同意<span style="color: #c0392b;">《优惠规则与条款》</span>协议。</small></span></span></span></span></p>', 10, '2020-04-24 13:54:46', '2025-05-31 08:53:20'),
(3, '新实时反水', '', 'https://api.xxxx.com/storage/uploads/activity/202009/06/activity_1599385114_KKMCvuFxud.png', '<p><span style="color: #e67e22;"><span style="font-size: 20px;"><strong><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>电子/捕鱼/棋牌时时返水</small></span></span></span></strong></span></span></p>\n<p><img src="https://cdn2.igsttech.com/Web.Portal/Image/Upload/Promotion/a4d5aa6551b94544bf6eb07b9c382a37.png" alt="" width="750" height="66" /><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>查询方式：登录账号-- </small></span></span></span></span></p>', 1, 0, '', '<p><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>1.时时返水只需在投注页面右下方点击即可领取时时返水金额。<br />2.天天返水会员无需提交申请，结算与派发时间如下：</small></span></span></span></span></p>\n<p><img src="https://cdn2.igsttech.com/Web.Portal/Image/Upload/Promotion/ffbceef89d12487c8faae77dd8190d76.jpg" alt="" width="750" height="100" /></p>', '', '', NULL, NULL, '即日起', 1, 0, 0, 'zh_cn', '<p><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>1.本活动以北京时间为计时区间，所获返水仅需1倍流水即可申请提款;</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>2.若会员未领取时时返水，系统将在次日北京时间15:00自动派发；<br />3.所有参与本活动的会员，即表示您已同意<span style="color: #c0392b;">《优惠规则与条款》</span>协议。</small></span></span></span></span></p>', 10, '2020-04-24 14:06:32', '2025-05-31 08:53:20'),
(4, '电子棋牌 VIP升级模式', '', 'https://api.xxxx.com/storage/uploads/activity/202009/10/activity_1599744235_kPuuONexyM.png', '<p><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>即日起在亚新娱乐城的每一笔电子游艺、开元棋牌永久累积打码，累积到一定标准，即可升级，每升一级即可获得相对应的等级礼金，等级礼金最高可获得688000元，还可获得无门槛要求的周周俸禄、月月俸禄。让您的会员账号变成永久收益的有价值的会员账号！</small></span></span></span></span></p>', 4, 3, '', '<p><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>会员无需提交申请，电子棋牌月俸禄将于北京时间每月4号12:00系统自动派发；<br />电子棋牌晋级礼金，电子棋牌周俸禄将于北京时间每周四12:00系统自动派发；</small></span></span></span></span></p>', '', '', NULL, NULL, '即日起', 1, 0, 0, 'zh_cn', '', 10, '2020-04-24 14:15:00', '2025-05-31 08:53:20'),
(5, '电子游艺 以小博大', '', '', '<p><img src="https://api.xxxx.com/storage/uploads/editor/202004/24/editor_1587738000_7zSjjaN0A1.png" /></p>\n<p><small>注：会员账户需低于5元方可申请本活动。</small><br /><small>例：会员存款50元，即可申请获得38元奖金，提款金额888元。</small></p>', 2, 2, '', '', 'https://api.xxxx.com/storage/uploads/activity/202004/24/activity_1587737808_QZuIAbY8T1.png', 'member_name,recharge_money', NULL, NULL, '即日起', 0, 0, 0, 'common', '<p><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>1.本活动以北京时间为计时区间，所获奖金 本金达到10倍流水即可申请提款；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>2.每位会员每日仅限申请一次；会员请在成功存款后，未进行任何投注前，前往<a href="https://9170pay.com/Activity" target="_blank" rel="noopener"><span style="color: #f39c12;">【优惠大厅】</span></a>提交申请；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>3.若会员存款后进行投注，则取消参与本活动资格；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>4.所有参与本活动的会员，不得同时参与其他存送活动；</small></span></span></span></span><br /><span style="font-size: 20px;"><span style="margin: 0cm 0cm 0.0001pt; text-align: justify;"><span style="font-family: Verdana,Geneva,sans-serif;"><span style="line-height: 150%;"><small>5.本活动仅限投注于电子游戏，※不可投注于：所有棋牌，捕鱼，桌面游戏、刮刮乐、21点、轮盘、百家乐、骰宝、视频扑克游戏、纸牌、街机游戏、所有Pontoon游戏、各种Craps游戏、赌场战争、娱乐场Holdem游戏、牌九、多旋转老虎机(地妖之穴、海洋公主、三倍利润、热带滚筒和部落生活) 、单轴老虎机、单线老虎机和六合彩，彩票大小，单双，质合，等50%概率游戏。<br />6.所有参与本活动的会员，即表示您已同意<span style="color: #c0392b;">《优惠规则与条款》</span>协议。</small></span></span></span></span></p>', 10, '2020-04-24 14:20:23', '2025-05-31 08:53:20'),
(11, '越南活动1', '', '', '<p>活动说明</p>', 3, 2, '', '<p>申请条件</p>', 'https://api.xxxx.com/storage/uploads/activity/202105/12/activity_1620827323_pOlTfktuFF.jpg', 'member_name,recharge_money', NULL, NULL, '所有都可以申请', 1, 1, 0, 'vi', '<p>活动规则</p>', 10, '2021-05-12 13:51:33', '2025-05-31 08:53:20'),
(12, 'VIP upgrade mode of electronic chess and card', '', 'https://api.xxxx.com/storage/uploads/activity/202106/02/activity_1622635252_cgRsjvyxyZ.png', '<p>From now on, every electronic game and Kaiyuan chess and card in Jinsha entertainment city will be played permanently. If they reach a certain standard, they can be upgraded. They can get the corresponding level of gift money for each level. The highest level of gift money can get 688000 yuan, and they can also get the weekly salary and monthly salary without threshold requirements. Let your member account become a valuable member account with permanent income!</p>', 4, 3, '', '<p>Members do not need to submit an application. The monthly salary of electronic chess and cards will be automatically distributed by the system at 12:00 on the 4th of each month, Beijing time;</p>\n<p>The weekly salary of electronic chess and cards will be automatically distributed by the system at 12:00 Beijing time every Thursday;</p>\n<p></p>', '', '', NULL, NULL, 'From now on', 1, 0, 0, 'en', '', 10, '2021-06-02 12:02:12', '2025-05-31 08:53:20'),
(13, 'Company''s contribution ratio', '', 'https://api.xxxx.com/storage/uploads/activity/202106/02/activity_1622635380_7h8jiuHR3p.png', '<p>Electronic / fishing / chess and cards always return to water</p>\n<p>Query method: login account--</p>', 1, 0, '', '<p>1. Just click on the bottom right of the betting page to get the amount of return water.</p>\n<p>2. There is no need to submit an application for daily return. The settlement and distribution time is as follows:</p>', '', '', NULL, NULL, 'From now on', 1, 0, 0, 'en', '<p>1. This activity takes Beijing time as the time interval, and the return water only needs one time of flow to apply for withdrawal;</p>\n<p>2. If the member does not receive the return water, the system will automatically distribute it at 15:00 Beijing time the next day;</p>\n<p>3. All members who participate in this activity mean that you have agreed to the preferential rules and conditions agreement.</p>', 10, '2021-06-02 12:04:20', '2025-05-31 08:53:20');
