INSERT INTO `game_hots` (`id`, `name`, `desc`, `en_name`, `en_desc`, `tw_name`, `tw_desc`, `th_name`, `th_desc`, `vi_name`, `vi_desc`, `icon_path`, `icon_path2`, `api_name`, `lang`, `is_new_window`, `jump_link`, `game_type`, `type`, `game_code`, `img_url`, `is_online`, `sort`, `created_at`, `updated_at`) VALUES
(1, 'AG视讯', '最真实的赌场环境，最美丽、最专业的荷官，为您呈现奢华百家乐，玩法多样不重复，为您献上现场精彩体验！', '', NULL, '', NULL, '', NULL, '', NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202106/23/gamehot_1624379840_d25DhnxElU.png', 'https://api.xxxx.com/storage/uploads/gamehot/202106/22/gamehot_1624377339_IKMYHgpOBK.png', 'AG', 'zh_cn', 0, '/#/Live', 1, 1, '', 'https://api.xxxx.com/storage/uploads/gamehot/202107/09/gamehot_1625782832_rmlatLG62P.png', 1, 2, '2021-06-19 08:24:10', '2025-05-31 08:53:20'),
(2, 'AG Live', 'The most realistic casino environment, the most beautiful and professional dealers, will present you with luxurious baccarat, the gameplay is diverse and not repeated, and will provide you with a wonderful live experience!', '', NULL, '', NULL, '', NULL, '', NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202106/23/gamehot_1624379840_d25DhnxElU.png', 'https://api.xxxx.com/storage/uploads/gamehot/202106/22/gamehot_1624377339_IKMYHgpOBK.png', 'AG', 'en', 0, '/#/Live', 1, 1, NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202107/09/gamehot_1625782832_rmlatLG62P.png', 1, 3, '2022-03-17 01:11:03', '2025-05-31 08:53:20'),
(4, 'AG Live', 'สภาพแวดล้อมของคาสิโนที่สมจริงที่สุด ดีลเลอร์ที่สวยงามและเป็นมืออาชีพที่สุด จะนำเสนอบาคาร่าที่หรูหราแก่คุณ รูปแบบการเล่นที่หลากหลายและไม่ซ้ำซากจำเจ และจะมอบประสบการณ์สดที่ยอดเยี่ยมแก่คุณ!', '', NULL, '', NULL, '', NULL, '', NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202106/23/gamehot_1624379840_d25DhnxElU.png', 'https://api.xxxx.com/storage/uploads/gamehot/202106/22/gamehot_1624377339_IKMYHgpOBK.png', 'AG', 'th', 0, '/#/Live', 1, 1, NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202107/09/gamehot_1625782832_rmlatLG62P.png', 1, 5, '2022-03-17 01:44:04', '2025-05-31 08:53:20'),
(5, 'AG Live', 'Môi trường sòng bạc thực tế nhất, những người chia bài đẹp và chuyên nghiệp nhất, sẽ giới thiệu cho bạn trò chơi baccarat sang trọng, cách chơi đa dạng và không lặp lại, và sẽ mang đến cho bạn trải nghiệm trực tiếp tuyệt vời!', '', NULL, '', NULL, '', NULL, '', NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202106/23/gamehot_1624379840_d25DhnxElU.png', 'https://api.xxxx.com/storage/uploads/gamehot/202106/22/gamehot_1624377339_IKMYHgpOBK.png', 'AG', 'vi', 0, '/#/Live', 1, 1, NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202107/09/gamehot_1625782832_rmlatLG62P.png', 1, 6, '2022-03-17 01:45:49', '2025-05-31 08:53:20'),
(6, 'AG視訊', '最真實的賭場環境，最美麗、最專業的荷官，為您呈現奢華百家樂，玩法多樣不重復，為您獻上現場精彩體驗！', '', NULL, '', NULL, '', NULL, '', NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202106/23/gamehot_1624379840_d25DhnxElU.png', 'https://api.xxxx.com/storage/uploads/gamehot/202106/22/gamehot_1624377339_IKMYHgpOBK.png', 'AG', 'zh_hk', 0, '/#/Live', 1, 1, NULL, 'https://api.xxxx.com/storage/uploads/gamehot/202107/09/gamehot_1625782832_rmlatLG62P.png', 1, 7, '2022-03-17 04:48:15', '2025-05-31 08:53:20');
