(205, 'levelup_slot_month', '电子升级月俸禄说明', 'levelup_slot', 'editor', '<p><span>如何申请每月俸禄？</span></p>\n<p>按您的等级计算，距离上次登录30天后再次登录即可自动到账，等级每月俸禄详情如下：</p>', '', '', '', 1, 0, 'zh_cn', '2020-12-26 07:28:51', '2021-01-24 09:03:38'),
(206, 'levelup_slot_month', '电子升级月俸禄说明', 'levelup_slot', 'editor', '<p>332</p>', '', '', '', 1, 0, 'zh_hk', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(207, 'levelup_slot_month', '电子升级月俸禄说明', 'levelup_slot', 'editor', '<p>332</p>', '', '', '', 1, 0, 'en', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(208, 'levelup_slot_month', '电子升级月俸禄说明', 'levelup_slot', 'editor', '<p>332</p>', '', '', '', 1, 0, 'th', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(209, 'levelup_slot_month', '电子升级月俸禄说明', 'levelup_slot', 'editor', '<p>332</p>', '', '', '', 1, 0, 'vi', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(210, 'levelup_live_activity', '真人升级活动详情', 'levelup_live', 'editor', '<h2><span>玩真人视讯永久累计打码，让您的会员账号变成永久收益金管家！</span></h2>\n<p>在亚新娱乐的每一笔真人投注都会永久累积，累积到一定标准，即可升级。<br />每升一级即可获得相对应的等级礼金，等级礼金最高可获得<span style="color: #ff0000;">748300</span>元，还有无门槛要求的月俸禄终身送不停，这就是您的会员账号金管家！</p>', '', '', '', 1, 0, 'zh_cn', '2020-12-26 07:28:51', '2021-01-24 09:04:39'),
(211, 'levelup_live_activity', '真人升级活动详情', 'levelup_live', 'editor', '', '', '', '', 1, 0, 'zh_hk', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(212, 'levelup_live_activity', '真人升级活动详情', 'levelup_live', 'editor', '', '', '', '', 1, 0, 'en', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
