(215, 'levelup_live_example', '真人升级活动举例', 'levelup_live', 'editor', '<p><span>例: 会员每一笔真人投注累计达到100万打码量即可获得等级礼金&nbsp;</span><span><span style="color: #ff0000;">200</span></span><span>元，每周可获得</span><span style="color: #ff0000;">1</span><span>0</span><span>元周俸禄， 每月可获得</span><span style="color: #ff0000;">5</span><span>0</span><span>元月俸禄， 当累计到</span><span style="color: #ff0000;">5</span><span>00</span><span>万有效投注，即可再次获得升级礼金</span><span style="color: #ff0000;">6</span><span><span style="color: #ff0000;">0</span>0</span><span>元，每周可获得</span><span style="color: #ff0000;">5</span><span><span style="color: #ff0000;">0</span></span><span>元周俸禄，每月可获得</span><span style="color: #ff0000;">20</span><span><span style="color: #ff0000;">0</span></span><span>元月俸禄！</span></p>', '', '', '', 1, 0, 'zh_cn', '2020-12-26 07:28:51', '2021-01-24 09:04:39'),
(216, 'levelup_live_example', '真人升级活动举例', 'levelup_live', 'editor', '', '', '', '', 1, 0, 'zh_hk', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(217, 'levelup_live_example', '真人升级活动举例', 'levelup_live', 'editor', '', '', '', '', 1, 0, 'en', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
