(219, 'levelup_live_example', '真人升级活动举例', 'levelup_live', 'editor', '', '', '', '', 1, 0, 'vi', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(220, 'levelup_live_level', '真人升级升级说明', 'levelup_live', 'editor', '<p><span>如何查询金管家等级？</span><br />请登入&ldquo;金管家升级版&rdquo;输入会员账号，进行自助查询有效投注、等级等明细。</p>\n<p><span>如何申请金管家等级礼金？</span><br />无需申请, 距离上次登录7天后再次登录即可自动到账，彩金无需打码，可直接提款。如：会员直接从等级2升级到到等级5，跨越3个等级，即可获得升级礼金： 55（等级3）+100（等级4）+200（等级5）=355元</p>\n<p><span></span>如何申请每周俸禄？</p>\n<p><br /><span>按您的等级计算，距离上次登录7天后再次登录即可自动到账，等级每周俸禄详情如下：</span></p>', '', '', '', 1, 0, 'zh_cn', '2020-12-26 07:28:51', '2021-01-24 09:04:39'),
(221, 'levelup_live_level', '真人升级升级说明', 'levelup_live', 'editor', '', '', '', '', 1, 0, 'zh_hk', '2020-12-26 07:28:51', '2020-12-26 07:28:51'),
(222, 'levelup_live_level', '真人升级升级说明', 'levelup_live', 'editor', '', '', '', '', 1, 0, 'en', '2020-12-26 07:28:51', '2020-12-26 07:28:51');
