INSERT INTO `system_notices` (`id`, `title`, `content`, `text_content`, `group_name`, `weight`, `url`, `is_app`, `is_open`, `lang`, `created_at`, `updated_at`) VALUES
(1, '电子升级大厅公告1', '免息借呗重磅升级；升级模式1级即可申请无利息借贷，0抵押，0担保！最高可借1880000元', NULL, '电子升级大厅', 0, NULL, 0, 1, 'common', '2020-12-19 08:06:44', '2020-12-19 08:06:44'),
(2, '信用借呗', '友情提醒：逾期未还款的会员系统将暂停发放电子棋牌升级模式周俸禄、月俸禄和真人升级模式月俸禄，直至还清后再正常派送。', NULL, 'credit', 0, NULL, 0, 1, 'common', '2020-12-19 08:06:44', '2020-12-19 08:06:44'),
(3, '信用借呗', '信用就是价值，价值就是金钱！因为信用，所以简单！', NULL, 'credit', 0, NULL, 0, 1, 'common', '2020-12-19 08:06:44', '2020-12-19 08:06:44'),
(4, '信用借呗', '温馨提示：【免息借呗】 单一会员最高可借款￥1880000元，0担保、0抵押、0利息，信用就是价值，价值就是金钱！', NULL, 'credit', 0, NULL, 0, 1, 'common', '2020-12-19 08:06:44', '2020-12-19 08:06:44'),
(5, '真人升级大厅公告', '永久累积视讯打码升级，等级礼金+月俸禄【终生领取】尊享时时返水，等级越高账号交易价值越高~', NULL, '真人升级大厅', 0, NULL, 0, 1, 'common', '2020-12-19 08:06:44', '2020-12-19 08:06:44'),
(7, '中国公告', '中国公告内容', NULL, 'main', 0, NULL, 0, 1, 'zh_cn', '2021-04-22 11:58:15', '2021-04-22 11:58:15'),
