CREATE TABLE IF NOT EXISTS `yuebao_plans` (
  `id` bigint(20) unsigned NOT NULL,
  `SettingName` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '计划标题',
  `MinAmount` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '最低购买金额',
  `MaxAmount` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '最高购买金额',
  `SettleTime` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '结算时间',
  `IsCycleSettle` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否循环结算/单次结算',
  `Rate` decimal(16,2) unsigned NOT NULL DEFAULT '0.00' COMMENT '利率',
  `TotalCount` decimal(16,2) unsigned NOT NULL DEFAULT '0.00' COMMENT '计划总金额',
  `LimitInterest` decimal(16,2) unsigned NOT NULL DEFAULT '0.00' COMMENT '会员封顶利息',
  `LimitOrderIntervalTime` int(10) unsigned DEFAULT NULL COMMENT '限制订单间隔时间',
  `InterestAuditMultiple` decimal(16,1) unsigned NOT NULL DEFAULT '1.0' COMMENT '利息码量倍数',
  `LimitUserOrderCount` int(11) NOT NULL DEFAULT '-1' COMMENT '会员最大购买总金额',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开放',
  `weight` int(10) unsigned NOT NULL DEFAULT '10' COMMENT '排序',
  `lang` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'zh_cn' COMMENT '语言类型',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

